mapper.select:
SELECT wq.*, sa.area_name
FROM water_quality wq
LEFT JOIN sea_area sa ON wq.area_id = sa.id


        AND wq.area_id = #{areaId}


        AND wq.monitor_time >= #{startDate}


        AND wq.monitor_time <= #{endDate}


ORDER BY wq.monitor_time DESC

SELECT DATE(monitor_time) AS monitor_date, AVG(salinity) AS avg_salinity, AVG(temperature) AS avg_temperature, AVG(dissolved_oxygen) AS avg_dissolved_oxygen, AVG(ph_value) AS avg_ph_value FROM water_quality
AND area_id = #{areaId}
AND monitor_time >= #{startDate}
AND monitor_time <= #{endDate}
GROUP BY DATE(monitor_time) ORDER BY monitor_date
